void coloresLeccionMenu(int n) {
	switch (n) {
	case 0:  Console::ForegroundColor = ConsoleColor::Black; break;
	case 1:  Console::ForegroundColor = ConsoleColor::Cyan; break;
	case 3:  Console::ForegroundColor = ConsoleColor::White; break;
	case 4:  Console::ForegroundColor = ConsoleColor::DarkGreen; break;
	case 5:  Console::ForegroundColor = ConsoleColor::Green; break;
	case 6:  Console::ForegroundColor = ConsoleColor::Gray; break;
	case 7:  Console::ForegroundColor = ConsoleColor::Yellow; break;
	case 8:  Console::ForegroundColor = ConsoleColor::Red; break;
	case 9:  Console::ForegroundColor = ConsoleColor::Magenta; break;
	default: Console::ResetColor(); break;
	}
}
void dibujarFondoLeccionMenu() {

	Console::CursorVisible = false;

	for (int i = 0; i < PRESENTACION_ALTO; i++) {
		for (int c = 0; c < PRESENTACION_ANCHO; c++) {
			if (FondoMenuLeccion[i][c] == 0) coloresLeccionMenu(0);
			if (FondoMenuLeccion[i][c] == 1) coloresLeccionMenu(1);
			if (FondoMenuLeccion[i][c] == 3) coloresLeccionMenu(3);
			if (FondoMenuLeccion[i][c] == 4) coloresLeccionMenu(4);
			if (FondoMenuLeccion[i][c] == 5) coloresLeccionMenu(5);
			if (FondoMenuLeccion[i][c] == 6) coloresLeccionMenu(6);
			if (FondoMenuLeccion[i][c] == 7) coloresLeccionMenu(7);

			cursorMenu(c, i); cout << (char)219;
		}
	}
	Console::ForegroundColor = ConsoleColor::White;

}

//Lógica fondo de salvador
